<?php if(!defined('ABSPATH')){exit;}class AuthMe_Auth{public function ajax_check_username(){check_ajax_referer('authme_nonce','nonce');$username=isset($_POST['username'])?sanitize_user($_POST['username']):'';if(empty($username)){wp_send_json_error(array('message'=>'Username is required.'));}if(!preg_match('/^[a-zA-Z]/',$username)){wp_send_json_error(array('message'=>'Username must start with an alphabet character.'));}if(!preg_match('/^[a-zA-Z][a-zA-Z0-9]{3,13}$/',$username)){wp_send_json_error(array('message'=>'Username must be 4–14 alphanumeric characters.'));}if(username_exists($username)){wp_send_json_error(array('message'=>'Username not available.'));}wp_send_json_success(array('message'=>'Username available.'));}public function ajax_check_email(){check_ajax_referer('authme_nonce','nonce');$email=isset($_POST['email'])?sanitize_email($_POST['email']):'';if(empty($email)|| !is_email($email)){wp_send_json_error(array('message'=>'Please enter a valid email address.'));}if(email_exists($email)){wp_send_json_error(array('message'=>'Email already registered.'));}wp_send_json_success(array('message'=>'Email available.'));}public function ajax_check_mobile(){check_ajax_referer('authme_nonce','nonce');$mobile=isset($_POST['mobile'])?sanitize_text_field($_POST['mobile']):'';if(empty($mobile)){wp_send_json_error(array('message'=>'Please enter a valid mobile number.'));}$args=array('meta_key'=>'mobile_number','meta_value'=>$mobile,'meta_compare'=>'=','number'=>1,'fields'=>'IDS');$users=get_users($args);if(!empty($users)){wp_send_json_error(array('message'=>'Mobile number already registered.'));}wp_send_json_success(array('message'=>'Mobile number available.'));}public function ajax_check_user_exists(){check_ajax_referer('authme_nonce','nonce');$identifier=isset($_POST['identifier'])?sanitize_text_field($_POST['identifier']):'';if(empty($identifier)){wp_send_json_error(array('message'=>'Please enter your username or email.'));}if(strpos($identifier,'@')!==false){$user=get_user_by('email',sanitize_email($identifier));}else{$user=get_user_by('login',$identifier);}if(!$user){wp_send_json_error(array('message'=>'User not found. Please check your credentials.'));}wp_send_json_success(array('message'=>'User found.','email'=>$user->user_email,));}public function ajax_login_user(){check_ajax_referer('authme_nonce','nonce');$identifier=isset($_POST['identifier'])?sanitize_text_field($_POST['identifier']):'';$password=isset($_POST['password'])?$_POST['password']:'';$remember=isset($_POST['remember'])&&$_POST['remember']==='true';$direct_login=isset($_POST['direct_login'])&&$_POST['direct_login']==='true';if(empty($identifier)||empty($password)){wp_send_json_error(array('message'=>'All fields are required.'));}if(strpos($identifier,'@')!==false){$user=get_user_by('email',sanitize_email($identifier));}else{$user=get_user_by('login',$identifier);}if(!$user){wp_send_json_error(array('message'=>'No account found. Please check your credentials.'));}if(in_array('administrator',(array)$user->roles)){wp_send_json_error(array('message'=>'Administrator accounts cannot log in here.'));}if(!wp_check_password($password,$user->user_pass,$user->ID)){wp_send_json_error(array('message'=>'Incorrect password. Please try again.'));}if($direct_login){wp_set_current_user($user->ID);wp_set_auth_cookie($user->ID,$remember);do_action('wp_login',$user->user_login,$user);$email_handler=new AuthMe_Email();$email_handler->send_email('login_alert',$user->user_email);wp_send_json_success(array('message'=>'Login successful! Welcome back, '.esc_html($user->display_name).'.',));}wp_send_json_success(array('message'=>'Credentials verified. Sending OTP…','email'=>$user->user_email,'user_id'=>$user->ID,'remember'=>$remember,));}public function ajax_register_user(){check_ajax_referer('authme_nonce','nonce');$user_data_raw=isset($_POST['user_data'])?wp_unslash($_POST['user_data']):'';if(empty($user_data_raw)){wp_send_json_error(array('message'=>'User data is missing.'));}$user_data=json_decode($user_data_raw,true);if(!$user_data||empty($user_data['username'])||empty($user_data['email'])||empty($user_data['password'])){wp_send_json_error(array('message'=>'Invalid user data.'));}$username=sanitize_user($user_data['username']);$email=sanitize_email($user_data['email']);$password=$user_data['password'];$mobile_number=isset($user_data['mobile_number'])?sanitize_text_field($user_data['mobile_number']):'';$mobile_region=isset($user_data['mobile_region'])?sanitize_text_field($user_data['mobile_region']):'';if(!empty($mobile_number)){$clean_mobile=preg_replace('/[^0-9]/','',$mobile_number);if(strlen($clean_mobile)<7||strlen($clean_mobile)>15){wp_send_json_error(array('message'=>'Invalid mobile number format.'));}}if(username_exists($username)){wp_send_json_error(array('message'=>'Username not available.'));}if(email_exists($email)){wp_send_json_error(array('message'=>'Email already registered.'));}$user_id=wp_insert_user(array('user_login'=>$username,'user_nicename'=>sanitize_title($username),'user_email'=>$email,'user_pass'=>$password,'role'=>'traveller',));if(is_wp_error($user_id)){wp_send_json_error(array('message'=>$user_id->get_error_message()));}if(!empty($mobile_number)){update_user_meta($user_id,'mobile_number',$mobile_number);}update_user_meta($user_id,'is_email_verified',1);update_user_meta($user_id,'is_number_verified',0);update_user_meta($user_id,'auth_method','normal_auth');wp_set_current_user($user_id);wp_set_auth_cookie($user_id,true);$email_handler=new AuthMe_Email();$new_user=get_userdata($user_id);$saved_mobile=get_user_meta($user_id,'mobile_number',true);$all_details=array('username'=>$new_user->user_login,'email'=>$new_user->user_email,);if(!empty($saved_mobile)){$all_details['mobile']=$saved_mobile;}$email_handler->send_email('register_success',$new_user->user_email,array('all_details'=>$all_details));wp_send_json_success(array('message'=>'Registration successful! Welcome aboard.',));}public function ajax_forgot_check_user(){check_ajax_referer('authme_nonce','nonce');$identifier=isset($_POST['identifier'])?sanitize_text_field($_POST['identifier']):'';if(empty($identifier)){wp_send_json_error(array('message'=>'Please enter your email or username.'));}if(strpos($identifier,'@')!==false){$user=get_user_by('email',sanitize_email($identifier));}else{$user=get_user_by('login',$identifier);}if(!$user){wp_send_json_error(array('message'=>'No account found with this detail. Please create one.',));}wp_send_json_success(array('email'=>$user->user_email,'user_id'=>$user->ID,));}public function ajax_reset_password(){check_ajax_referer('authme_nonce','nonce');$email=isset($_POST['email'])?sanitize_email($_POST['email']):'';$new_password=isset($_POST['new_password'])?wp_unslash($_POST['new_password']):'';if(empty($email)||empty($new_password)){wp_send_json_error(array('message'=>'All fields are required.'));}if(strlen($new_password)<8){wp_send_json_error(array('message'=>'Password must be at least 8 characters.'));}$user=get_user_by('email',$email);if(!$user){wp_send_json_error(array('message'=>'User not found.'));}wp_set_password($new_password,$user->ID);$email_handler=new AuthMe_Email();$email_handler->send_password_changed_email($email,$user->display_name);wp_send_json_success(array('message'=>'Password reset successfully! You can now log in.',));}public function ajax_google_auth_callback(){check_ajax_referer('authme_nonce','nonce');$access_token=isset($_POST['token'])?sanitize_text_field($_POST['token']):'';if(empty($access_token)){wp_send_json_error(array('message'=>'Authentication token missing.'));}$userinfo_url='https://www.googleapis.com/oauth2/v3/userinfo?access_token='.$access_token;$response=wp_remote_get($userinfo_url);if(is_wp_error($response)){wp_send_json_error(array('message'=>'Failed to fetch user data from Google API.'));}$data=json_decode(wp_remote_retrieve_body($response),true);if(empty($data['email'])){wp_send_json_error(array('message'=>'Invalid data received from Google.'));}$email=sanitize_email($data['email']);$name=isset($data['name'])?sanitize_text_field($data['name']):strstr($email,'@',true);$profile_pic=isset($data['picture'])?esc_url_raw($data['picture']):'';$email_verified= !empty($data['email_verified'])?1:0;$people_url='https://people.googleapis.com/v1/people/me?personFields=phoneNumbers';$people_response=wp_remote_get($people_url,array('headers'=>array('Authorization'=>'Bearer '.$access_token)));$phone_number='';$is_number_verified=0;if(!is_wp_error($people_response)){$people_data=json_decode(wp_remote_retrieve_body($people_response),true);if(!empty($people_data['phoneNumbers'])&&is_array($people_data['phoneNumbers'])){$best_phone='';$best_phone_is_verified=0;foreach($people_data['phoneNumbers']as $phone){if(!empty($phone['value'])){$is_verified= !empty($phone['metadata']['verified'])?1:0;if(!empty($phone['canonicalForm'])){$formatted_phone=sanitize_text_field($phone['canonicalForm']);}else{$formatted_phone=sanitize_text_field($phone['value']);}$formatted_phone=str_replace(array(' ','-','(',')'),'',$formatted_phone);if(empty($best_phone)||($best_phone_is_verified===0&&$is_verified===1)){$best_phone=$formatted_phone;$best_phone_is_verified=$is_verified;}}}if(!empty($best_phone)){$phone_number=$best_phone;$is_number_verified=$best_phone_is_verified;}}}$user=get_user_by('email',$email);if($user){$existing_auth_method=get_user_meta($user->ID,'auth_method',true);if($existing_auth_method!=='google_auth'){wp_send_json_error(array('message'=>'Account already exists. Please login with password.'));}$has_phone=false;if(!empty($profile_pic)){update_user_meta($user->ID,'profile_pic',$profile_pic);}if(!empty($phone_number)){update_user_meta($user->ID,'mobile_number',$phone_number);update_user_meta($user->ID,'is_number_verified',$is_number_verified);$has_phone=true;}else{$existing_phone=get_user_meta($user->ID,'mobile_number',true);$has_phone= !empty($existing_phone);}$redirect_url='';if(!$has_phone){global $wpdb;$table_name=$wpdb->prefix.'admin_management';$profile_page_id=$wpdb->get_var($wpdb->prepare("SELECT page_id FROM $table_name WHERE name = %s",'My Profile'));if($profile_page_id){$redirect_url=get_permalink($profile_page_id);}}wp_set_current_user($user->ID);wp_set_auth_cookie($user->ID,true);do_action('wp_login',$user->user_login,$user);$email_handler=new AuthMe_Email();$email_handler->send_email('google_login_alert',$user->user_email);wp_send_json_success(array('message'=>'Welcome back, '.esc_html($user->display_name).'!','redirect_url'=>$redirect_url));}else{$base_username=strstr($email,'@',true);$username=$base_username;$counter=1;while(username_exists($username)){$username=$base_username.$counter;$counter++;}$user_id=wp_insert_user(array('user_login'=>$username,'user_nicename'=>sanitize_title($username),'user_email'=>$email,'user_pass'=>wp_generate_password(16,true),'display_name'=>$name,'role'=>'traveller','user_registered'=>current_time('mysql'),));if(is_wp_error($user_id)){wp_send_json_error(array('message'=>'Account creation failed: '.$user_id->get_error_message()));}update_user_meta($user_id,'auth_method','google_auth');update_user_meta($user_id,'is_email_verified',$email_verified);update_user_meta($user_id,'is_number_verified',$is_number_verified);update_user_meta($user_id,'profile_pic',$profile_pic);$has_phone=false;if(!empty($phone_number)){update_user_meta($user_id,'mobile_number',$phone_number);$has_phone=true;}update_user_meta($user_id,'wp_capabilities',array('traveller'=>true));$redirect_url='';if(!$has_phone){global $wpdb;$table_name=$wpdb->prefix.'admin_management';$profile_page_id=$wpdb->get_var($wpdb->prepare("SELECT page_id FROM $table_name WHERE name = %s",'My Profile'));if($profile_page_id){$redirect_url=get_permalink($profile_page_id);}}wp_set_current_user($user_id);wp_set_auth_cookie($user_id,true);do_action('wp_login',$username,get_userdata($user_id));$email_handler=new AuthMe_Email();$new_user=get_userdata($user_id);$saved_mobile=get_user_meta($user_id,'mobile_number',true);$all_details=array('username'=>$new_user->user_login,'email'=>$new_user->user_email,);if(!empty($saved_mobile)){$all_details['mobile']=$saved_mobile;}$email_handler->send_email('google_register_success',$new_user->user_email,array('all_details'=>$all_details));wp_send_json_success(array('message'=>'Account created successfully! Welcome, '.esc_html($name).'.','redirect_url'=>$redirect_url));}}}